(function($){$(window).on("elementor/frontend/init",function(){var WPMOZOScrollText=elementorModules.frontend.handlers.Base.extend({bindEvents:function(){this.change()},change:function(){jQuery(document).ready(function($){if($('.wpmozo_scroll_text').length>0){gsap.registerPlugin(ScrollTrigger);$('.wpmozo_scroll_text').each(function(){let $thisObj=$(this),$wrapObj=$thisObj.find('.wpmozo_scroll_text_wrap');let $innerWrap=$wrapObj.find('.wpmozo_scroll_text_inner'),originalText=$innerWrap.text().trim(),effect=$wrapObj.data('scroll_effect')||'fade',splitType=$wrapObj.data('split')||'word';let startOne=$wrapObj.data('animation_start_element_pos')||'0%',startTwo=$wrapObj.data('animation_start_viewport_pos')||'80%',endOne=$wrapObj.data('animation_end_element_pos')||'0%',endTwo=$wrapObj.data('animation_end_viewport_pos')||'40%';let start=startOne+' '+startTwo,end=endOne+' '+endTwo;$innerWrap.addClass(`wpmozo_scroll_${splitType}_${effect}`);$innerWrap.html('');let spans=[];if('letter'===splitType){let words=originalText.split(' ');words.forEach((word,wIdx)=>{let wordSpan=$('<span>',{class:'wpmozo_st_word'});for(let i=0;i<word.length;i++){let letterSpan=$('<span>',{class:'wpmozo_st_letter',text:word[i]});wordSpan.append(letterSpan);spans.push(letterSpan[0])}
if(wIdx!==words.length-1){let spaceSpan=$('<span>',{class:'wpmozo_st_letter',text:'\u00A0'});wordSpan.append(spaceSpan);spans.push(spaceSpan[0])}
$innerWrap.append(wordSpan)})}else{originalText.split(/\s+/).forEach((word,i,arr)=>{let span=$('<span>',{class:'wpmozo_st_word',text:word+(i===arr.length-1?'':' ')});$innerWrap.append(span);spans.push(span[0])})}
let tl=gsap.timeline({scrollTrigger:{trigger:$thisObj[0],start:start,end:end,scrub:!0}});spans.forEach((span,i)=>{tl.to(span,{onStart:()=>span.classList.add('visible'),onReverseComplete:()=>span.classList.remove('visible')})})})}})},});elementorFrontend.elementsHandler.attachHandler("wpmozo_ae_scroll_text",WPMOZOScrollText)})})(jQuery)